function StructDreamTripGrid:StructDreamTripGrid()
    ---@type number 平台下标
    self.index = 0

    ---@type table<string,StructDreamTripEventInfo> 格子上的事件数据
    self.eventMap = {}

    ---@type table<StructDreamTripEventInfo> 格子上的事件数据
    self.eventList = {}
end

function StructDreamTripGrid:SaveData(data)
    self.index = data.index

    self.eventMap = {}

    ---@type table<StructDreamTripEventInfo>
    local indexList = data.indexList or {}
    ---@param v StructDreamTripEventInfo
    for k,v in ipairs(indexList) do
        self.eventMap[v.eventId] = v
    end
    self:UpdateEventList()
end

function StructDreamTripGrid:UpdateEventList()
    self.eventList = {}
    for k,v in pairs(self.eventMap) do
        table.insert(self.eventList,v)
    end
    self:SortEventList()
end

function StructDreamTripGrid:SortEventList()
    table.sort(self.eventList,function(a,b)
        local typeA,typeB = a.eventType
        local priorityA = StructDreamTripGrid.SORTEVENTTYPE[typeA] or 0
        local priorityB = StructDreamTripGrid.SORTEVENTTYPE[typeB] or 0
        return priorityA > priorityB
    end)
end

---@param eventInfo StructDreamTripEventInfo
function StructDreamTripGrid:UpdateEventInfo(eventInfo)
    if not eventInfo then return end
    local eventId = eventInfo.eventId
    self.eventMap[eventId] = eventInfo
    self:UpdateEventList()
end

---@return StructDreamTripEventInfo
function StructDreamTripGrid:GetDreamTripEventInfoById(eventId)
