end

function StructDreamTripGrid:CheckGridIsFinish()
    local finishNum = 0
    ---@param v StructDreamTripEventInfo
    for i,v in ipairs(self.eventList) do
        if v:CheckIsFinishEvent() then
            finishNum = finishNum + 1
        end
    end
    return finishNum >= #self.eventList
end

